+    function activePresenterTour() {
+      return presenterModeId ? presenterTours[presenterModeId] || [] : [];
+    }
+
+    function presenterStepRecord() {
+      const tour = activePresenterTour();
+      if (!tour.length || presenterStepIndex < 0 || presenterStepIndex >= tour.length) {
+        return null;
+      }
+      return tour[presenterStepIndex];
+    }
+
+    function updatePresenterUi(statusMessage = null) {
+      const tour = activePresenterTour();
+      const step = presenterStepRecord();
+      els.presenterStart.disabled = !!step;
+      els.presenterPrev.disabled = !step || presenterStepIndex <= 0;
+      els.presenterNext.disabled = !step || presenterStepIndex >= tour.length - 1;
+      els.presenterSkip.disabled = !step;
+      els.presenterReset.disabled = !step;
+
+      if (!step) {
+        els.presenterStep.textContent = "Idle";
+        els.presenterSummary.textContent = statusMessage || "Presenter mode is idle. Start the guided tour to step through the strongest runtime, resilience, and evidence moments in sequence.";
+        els.presenterNote.textContent = "Reset restores the pre-tour showcase state so ad hoc exploration and scripted presentation can share one page safely.";
+        return;
+      }
+
+      const runtimeFallback = step.id === "runtime-honesty" && !frankenRuntime
+        ? "Runtime is unavailable, so present the explicit packaging diagnosis instead of a live WASM success path."
+        : step.note;
+      els.presenterStep.textContent = `Step ${presenterStepIndex + 1} of ${tour.length}: ${step.title}`;
+      els.presenterSummary.textContent = statusMessage || step.summary;
+      els.presenterNote.textContent = runtimeFallback;
+    }
+
+    async function applyShowcaseStateSnapshot(snapshot, reason) {
+      const sample = findSampleById(snapshot.sample, editorSamples[0]);
+      const spotlight = findSampleById(snapshot.spotlight || snapshot.sample, sample);
+
+      currentSample = sample;
+      spotlightSample = spotlight;
+      galleryFilter = galleryCategories.includes(snapshot.galleryFilter) ? snapshot.galleryFilter : "all";
+      galleryQuery = typeof snapshot.galleryQuery === "string" ? snapshot.galleryQuery : "";
+      compareSampleIds = Array.isArray(snapshot.compare) ? snapshot.compare.slice(0, 2) : [];
+      layoutLabFocus = ["overview", "cycles", "crossings", "budget", "legibility"].includes(snapshot.layoutLabFocus) ? snapshot.layoutLabFocus : "overview";
+      studioState = normalizeStudioState(snapshot.studio || defaultStudioState);
+      els.input.value = typeof snapshot.source === "string" ? snapshot.source : sample.code;
+      els.gallerySearch.value = galleryQuery;
+      applyShellStateSnapshot(snapshot.shells);
+
+      createSampleButtons();
+      renderFeatureStrip();
+      renderFilterControls();
+      renderStyleStudio();
+      setLayoutLabFocusButtons();
+      updateEditorChrome();
+      if (frankenRuntime) {
+        await frankenRuntime.init(buildRuntimeDiagramOptions());
+      }
+      await renderSpotlight();
+      await renderGallery();
+      await renderAll({ reason, immediate: true });
+    }
+
+    async function jumpToSection(sectionId) {
+      const section = document.getElementById(sectionId);
+      if (section) {
+        section.scrollIntoView({ behavior: motionBehavior(), block: "start" });
+      }
+    }
+
+    async function applyPresenterStep(action = "next") {
+      const step = presenterStepRecord();
+      if (!step) {
+        updatePresenterUi();
+        return;
+      }
+
+      await applyShowcaseStateSnapshot(
+        {
+          sample: step.sampleId,
+          spotlight: step.spotlightId || step.sampleId,
+          galleryFilter: "all",
+          galleryQuery: "",
+          compare: [],
+          layoutLabFocus: step.layoutLabFocus || "overview",
+          studio: defaultStudioState,
+          source: step.source || findSampleById(step.sampleId, editorSamples[0]).code,
+          shells: presenterBaseState?.shells || collectShellState()
+        },
+        `presenter-${step.id}`
+      );
+      if (step.runDeterminism) {
+        await runDeterminismCheck({ runCount: step.runDeterminism, reason: `presenter-${step.id}` });
+      }
+      await jumpToSection(step.sectionId);
+      updatePresenterUi(action === "skip" ? `Skipped ahead to ${step.title}. ${step.summary}` : null);
+    }
+
+    async function startPresenterMode() {
+      presenterBaseState = collectUrlState();
+      presenterModeId = "main-demo";
+      presenterStepIndex = 0;
+      syncUrlState("push");
+      await applyPresenterStep("start");
+    }
+
+    async function movePresenterStep(delta, action) {
+      const tour = activePresenterTour();
+      if (!tour.length) {
+        return;
+      }
+      presenterStepIndex = Math.max(0, Math.min(presenterStepIndex + delta, tour.length - 1));
+      syncUrlState("push");
+      await applyPresenterStep(action);
+    }
+
+    async function resetPresenterMode() {
+      presenterModeId = "";
+      presenterStepIndex = -1;
+      if (presenterBaseState) {
+        await applyShowcaseStateSnapshot(presenterBaseState, "presenter-reset");
+      }
+      presenterBaseState = null;
+      syncUrlState("replace");
+      updatePresenterUi("Presenter mode reset. The page has been restored to the pre-tour state.");
     }

